    15→function SummarySection({ label, items }: { label: string; items: string[] }) {
    16→  const [open, setOpen] = useState(false);
    17→  if (items.length === 0) return null;
    18→  return (
    19→    <Box>
    20→      <UnstyledButton onClick={() => setOpen((v) => !v)} style={{ display: "flex", alignItems: "center", gap: 6, width: "100%" }}>
    21→        <Text size="xs" fw={600}>{label} ({items.length})</Text>
    22→        <Text size="xs" c="dimmed">{open ? "▲" : "▼"}</Text>
    23→      </UnstyledButton>
    24→      <Collapse in={open}>
    25→        {items.map((item, i) => <Text key={i} size="xs" c="dimmed" pl={8} style={{ lineHeight: "18px" }}>· {item}</Text>)}
    26→      </Collapse>
    27→    </Box>
    28→  );
    29→}
    30→
    31→function CodeLearningSections({ items }: { items: Array<{ path: string; finding: string }> }) {
    32→  const [open, setOpen] = useState(false);
    33→  if (items.length === 0) return null;
    34→  return (
    35→    <Box>
    36→      <UnstyledButton onClick={() => setOpen((v) => !v)} style={{ display: "flex", alignItems: "center", gap: 6, width: "100%" }}>
    37→        <Text size="xs" fw={600}>Code learnings ({items.length})</Text>
    38→        <Text size="xs" c="dimmed">{open ? "▲" : "▼"}</Text>
    39→      </UnstyledButton>
    40→      <Collapse in={open}>
    41→        {items.map((item, i) => (
    42→          <Box key={i} pl={8} mb={4}>
    43→            <Text size="xs" ff="monospace" c="violet" fw={600}>{item.path}</Text>
    44→            <Text size="xs" c="dimmed">{item.finding}</Text>
    45→          </Box>
    46→        ))}
    47→      </Collapse>
    48→    </Box>
    49→  );
    50→}
    51→
    52→function SummaryCard({ summary }: { summary: CheckpointSummary }) {
    53→  return (
    54→    <Box style={{ backgroundColor: "light-dark(var(--mantine-color-teal-0), var(--mantine-color-dark-7))", borderBottom: "1px solid light-dark(var(--mantine-color-teal-2), var(--mantine-color-teal-8))", padding: "12px 14px", display: "flex", flexDirection: "column", gap: 8 }}>
    55→      <Text size="xs" fw={700} c="teal" tt="uppercase" style={{ letterSpacing: 0.6 }}>Summary</Text>
