   279→export function subscribeToUpdates(onUpdate: () => void): () => void {
   280→  let ws: WebSocket | null = null;
   281→  let timer: ReturnType<typeof setTimeout> | null = null;
   282→  let closed = false;
   283→  let delay = 1000;
   284→
   285→  function connect() {
   286→    if (closed) return;
   287→    ws = new WebSocket(WS_URL);
   288→
   289→    ws.onopen = () => {
   290→      delay = 1000; // reset backoff on successful connection
   291→    };
   292→
   293→    ws.onmessage = (e) => {
   294→      try {
   295→        const msg = JSON.parse(e.data as string) as { type: string };
   296→        if (msg.type === "sessions_updated") onUpdate();
   297→      } catch {
   298→        // ignore malformed messages
   299→      }
   300→    };
   301→
   302→    ws.onclose = () => {
   303→      if (closed) return;
   304→      timer = setTimeout(() => {
   305→        delay = Math.min(delay * 2, 30000);
   306→        connect();
   307→      }, delay);
   308→    };
   309→
   310→    ws.onerror = () => {
   311→      ws?.close();
   312→    };
   313→  }
   314→
   315→  connect();
   316→
   317→  return () => {
   318→    closed = true;
   319→    if (timer !== null) clearTimeout(timer);
   320→    ws?.close();
   321→  };
   322→}
