     9→function CheckpointCard({ checkpoint, onPress }: { checkpoint: Checkpoint; onPress: () => void }) {
    10→  const title = checkpoint.summary?.intent ?? checkpoint.checkpointId;
    11→  const shortId = checkpoint.checkpointId.slice(0, 12);
    12→  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
    13→  const tokStr = outTokens >= 1000
    14→    ? `${(outTokens / 1000).toFixed(1)}k tokens`
    15→    : outTokens > 0 ? `${outTokens} tokens` : null;
    16→  const fileCount = checkpoint.filesTouched.length;
    17→
    18→  return (
    19→    <UnstyledButton
    20→      onClick={onPress}
    21→      style={{ width: "100%", display: "block", padding: "16px 20px", borderBottom: "1px solid var(--mantine-color-dark-4)" }}
    22→      styles={{ root: { "&:hover": { backgroundColor: "var(--mantine-color-dark-5)" } } }}
    23→    >
    24→      <Group justify="space-between" align="flex-start" wrap="nowrap" gap="xl">
    25→        <Box style={{ flex: 1, minWidth: 0 }}>
    26→          <Text fw={600} size="sm" mb={6} style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
    27→            {title}
    28→          </Text>
    29→          <Group gap={6} wrap="wrap" align="center">
    30→            <Code fz={11} style={{ borderRadius: 4, padding: "1px 6px" }}>{shortId}</Code>
    31→            {checkpoint.createdAt && (
    32→              <>
    33→                <Text size="xs" c="dimmed">·</Text>
    34→                <TimeAgo iso={checkpoint.createdAt} />
    35→              </>
    36→            )}
    37→            {checkpoint.branch && (
    38→              <>
    39→                <Text size="xs" c="dimmed">·</Text>
    40→                <Badge variant="outline" color="teal" size="xs" radius="sm">{checkpoint.branch}</Badge>
    41→              </>
    42→            )}
    43→            <Text size="xs" c="dimmed">·</Text>
    44→            <Badge variant="outline" color="orange" size="xs" radius="sm" ff="monospace">Claude Code</Badge>
    45→          </Group>
    46→        </Box>
    47→
    48→        <Group gap={6} style={{ flexShrink: 0, alignSelf: "center" }} wrap="nowrap">
    49→          {fileCount > 0 && (
    50→            <Text size="xs" c="dimmed">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>
    51→          )}
    52→          {checkpoint.sessionCount > 0 && (
    53→            <>
    54→              <Text size="xs" c="dimmed">·</Text>
    55→              <Text size="xs" c="dimmed">{checkpoint.sessionCount} session{checkpoint.sessionCount !== 1 ? "s" : ""}</Text>
    56→            </>
    57→          )}
    58→          {tokStr && (
    59→            <>
    60→              <Text size="xs" c="dimmed">·</Text>
    61→              <Text size="xs" c="dimmed">{tokStr}</Text>
    62→            </>
    63→          )}
    64→        </Group>
    65→      </Group>
    66→    </UnstyledButton>
    67→  );
