   340→function groupEvents(events: Event[]): DisplayItem[] {
   341→  const postMap = new Map<string, Event>();
   342→  for (const event of events) {
   343→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   344→      const d = event.data as Record<string, unknown>;
   345→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   346→      if (id) postMap.set(id, event);
   347→    }
   348→  }
   349→
   350→  type RawItem =
   351→    | { kind: "event"; event: Event }
   352→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   353→
   354→  const raw: RawItem[] = [];
   355→  const consumed = new Set<number>();
   356→
   357→  for (const event of events) {
   358→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   359→    if (event.event === "PreToolUse") {
   360→      const d = event.data as Record<string, unknown>;
   361→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   362→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   363→      if (post) consumed.add(post.id);
   364→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   365→      continue;
   366→    }
   367→    raw.push({ kind: "event", event });
   368→  }
   369→
   370→  const isGroupable = (item: RawItem) =>
   371→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   372→
   373→  const result: DisplayItem[] = [];
   374→  let i = 0;
   375→  while (i < raw.length) {
   376→    if (isGroupable(raw[i])) {
   377→      const group: ToolUseData[] = [];
   378→      while (i < raw.length && isGroupable(raw[i])) {
   379→        const item = raw[i];
   380→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   381→        i++;
   382→      }
   383→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   384→    } else {
   385→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   386→      i++;
   387→    }
   388→  }
   389→  return result;
   390→}
