   552→// ── Search snippet helpers ─────────────────────────────────────────────────────
   553→
   554→function extractMatchTerms(snippet: string): string[] {
   555→  const terms: string[] = [];
   556→  const re = /«([^»]+)»/g;
   557→  let m: RegExpExecArray | null;
   558→  while ((m = re.exec(snippet)) !== null) terms.push(m[1]);
   559→  return [...new Set(terms)];
   560→}
   561→
   562→// ── Source log event ID extractor ─────────────────────────────────────────────
   563→
   564→function getItemSourceIds(item: RenderItem): number[] {
   565→  if (item.kind === "event") {
   566→    const ids = item.event._sourceLogEventId != null ? [item.event._sourceLogEventId] : [];
   567→    if (item.event._extraSourceLogEventIds) ids.push(...item.event._extraSourceLogEventIds);
   568→    return ids;
   569→  }
   570→  if (item.kind === "claudeTurn") {
   571→    const ids: number[] = [];
   572→    for (const group of item.toolGroups) {
   573→      for (const tool of group) {
   574→        if (tool.pre._sourceLogEventId != null) ids.push(tool.pre._sourceLogEventId);
   575→        if (tool.pre._extraSourceLogEventIds) ids.push(...tool.pre._extraSourceLogEventIds);
   576→        if (tool.post?._sourceLogEventId != null) ids.push(tool.post._sourceLogEventId);
   577→        if (tool.post?._extraSourceLogEventIds) ids.push(...tool.post._extraSourceLogEventIds);
   578→      }
   579→    }
   580→    if (item.stop?._sourceLogEventId != null) ids.push(item.stop._sourceLogEventId);
   581→    if (item.stop?._extraSourceLogEventIds) ids.push(...item.stop._extraSourceLogEventIds);
   582→    return ids;
   583→  }
   584→  return [];
   585→}
