   587→export function SessionDetail() {
   588→  const navigate = useNavigate();
   589→  const { sessionId } = useParams<{ sessionId: string }>();
   590→  const [searchParams] = useSearchParams();
   591→  const location = useLocation();
   592→  const targetLogEventId = searchParams.get("logEventId") ? parseInt(searchParams.get("logEventId")!) : null;
   593→  const searchSnippet = (location.state as { snippet?: string; contentType?: string } | null)?.snippet ?? null;
   594→  const searchContentType = (location.state as { snippet?: string; contentType?: string } | null)?.contentType ?? null;
   595→  const [highlightActive, setHighlightActive] = useState(false);
   596→  const scrolledRef = useRef(false);
   597→  const viewportRef = useRef<HTMLDivElement>(null);
   598→  const logEventsRef = useRef<LogEventItem[]>([]);
   599→  const [session, setSession] = useState<Session | null>(null);
   600→  const [latestCheckpoint, setLatestCheckpoint] = useState<SessionCheckpoint | null>(null);
   601→  const [items, setItems] = useState<RenderItem[]>([]);
   602→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   603→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   604→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   605→  const [spawning, setSpawning] = useState(false);
   606→  const [loading, setLoading] = useState(true);
   607→  const [error, setError] = useState<string | null>(null);
   608→
   609→  const id = sessionId!;
   610→  const { setCrumbs } = useBreadcrumb();
   611→
   612→  function applyCheckpoints(logEvs: LogEventItem[], checkpoints: SessionCheckpoint[]) {
   613→    const grouped = groupEvents(logEventsToEvents(logEvs));
   614→    const merged: DisplayItem[] = [];
   615→    let cpIdx = 0;
   616→    const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   617→    const latest = sortedCps[sortedCps.length - 1] ?? null;
   618→    setLatestCheckpoint(latest);
   619→    setOpenItems(latest?.summary?.openItems ?? []);
   620→
   621→    for (const item of grouped) {
   622→      const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   623→      while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   624→        merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   625→      }
   626→      merged.push(item);
   627→    }
   628→    while (cpIdx < sortedCps.length) merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   629→    setItems(groupClaudeTurns(merged));
   630→  }
   631→
   632→  // Initial load
   633→  useEffect(() => {
   634→    Promise.all([fetchSession(id), fetchLogEvents(id), fetchSessionCheckpoints(id)])
   635→      .then(([s, logEvs, checkpoints]) => {
   636→        logEventsRef.current = logEvs;
   637→        setSession(s);
   638→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   639→        const repo = s.repoName ?? null;
   640→        const shortId = s.sessionId.slice(0, 8) + "…";
   641→        if (user) {
   642→          setUserInfo({
   643→            name: s.gitUserName ?? user,
   644→            avatarUrl: s.gitUserName ? `https://github.com/${s.gitUserName}.png?size=40` : undefined,
   645→          });
   646→        }
   647→        setCrumbs([
   648→          ...(user ? [{ label: user, path: "/" }] : []),
   649→          ...(repo ? [{ label: repo, path: "/" }] : []),
   650→          { label: shortId },
   651→        ]);
   652→        applyCheckpoints(logEvs, checkpoints);
   653→        setError(null);
   654→      })
   655→      .catch((err: unknown) => setError(String(err)))
   656→      .finally(() => setLoading(false));
   657→  }, [id]);
   658→
   659→  // Live updates: re-fetch checkpoints and log events when the server broadcasts a change
   660→  useEffect(() => {
   661→    return subscribeToUpdates(() => {
   662→      Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
   663→        .then(([logEvs, checkpoints]) => applyCheckpoints(logEvs, checkpoints))
   664→        .catch(() => undefined);
   665→    });
   666→  }, [id]);
   667→
   668→  // Step 1: activate highlight once items are loaded (triggers Collapse expand + mark rendering)
   669→  useEffect(() => {
   670→    if (targetLogEventId === null || items.length === 0 || scrolledRef.current) return;
   671→    const t = setTimeout(() => {
   672→      setHighlightActive(true);
   673→      scrolledRef.current = true;
   674→      setTimeout(() => setHighlightActive(false), 10000);
   675→    }, 150);
   676→    return () => clearTimeout(t);
   677→  }, [items, targetLogEventId]);
   678→
   679→  // Step 2: once highlightActive is true (marks rendered, Collapses expanding), scroll to first <mark>
   680→  useEffect(() => {
   681→    if (!highlightActive || targetLogEventId === null) return;
   682→    // Wait for Collapse animations (~200ms) to reach their final layout before measuring
   683→    const t = setTimeout(() => {
   684→      requestAnimationFrame(() => {
   685→        // Resolve UUID for the target logEventId, then find the most precise element
   686→        const uuid = logEventsRef.current.find((le) => le.id === targetLogEventId)?.uuid ?? null;
   687→        const el = (
   688→          (uuid ? document.getElementById(uuid) : null)
   689→          ?? document.getElementById(`log-event-${targetLogEventId}`)
   690→          ?? document.querySelector(`[data-log-event-id="${targetLogEventId}"]`)
   691→        ) as HTMLElement | null;
   692→        const viewport = viewportRef.current;
   693→        if (!el || !viewport) return;
   694→        const targetRect = el.getBoundingClientRect();
   695→        const vpRect = viewport.getBoundingClientRect();
   696→        const scrollTop = viewport.scrollTop + targetRect.top - vpRect.top - viewport.clientHeight / 2 + targetRect.height / 2 + 16;
   697→        viewport.scrollTo({ top: Math.max(0, scrollTop), behavior: "smooth" });
   698→      });
   699→    }, 250);
   700→    return () => clearTimeout(t);
   701→  }, [highlightActive, targetLogEventId]);
   702→
   703→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
   704→  if (error) return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   705→
   706→  return (
