   716→        </UnstyledButton>
   717→      )}
   718→      {session?.childSessionIds?.map((childId) => (
   719→        <UnstyledButton
   720→          key={childId}
   721→          onClick={() => navigate(`/sessions/${childId}`, { state: { title: childId.slice(0, 8) + "…" } })}
   722→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-green-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-green-2)", padding: "8px 14px" }}
   723→        >
   724→          <Text size="xs" c="green">↓ Continued as</Text>
   725→          <Text size="xs" c="green" ff="monospace" fw={600} td="underline">{childId.slice(0, 8)}…</Text>
   726→        </UnstyledButton>
   727→      ))}
   728→
   729→      {latestCheckpoint?.summary && (
   730→        <Box style={{
   731→          borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
   732→          padding: "16px 20px",
