   742→              </Text>
   743→              {openItems.map((item, i) => {
   744→                const selectable = item.status === "open";
   745→                const statusColor = item.status === "complete" ? "teal" : item.status === "in_progress" ? "orange" : item.status === "na" ? "gray" : "blue";
   746→                const statusLabel = item.status === "in_progress" ? "in progress" : item.status === "na" ? "n/a" : item.status;
   747→                return (
