   786→                              if (s !== "open") setSelectedItems((prev) => { const n = new Set(prev); n.delete(i); return n; });
   787→                            }}
   788→                          >
   789→                            {s === "in_progress" ? "in progress" : s === "na" ? "n/a" : s}
   790→                          </Menu.Item>
   791→                        ))}
   792→                      </Menu.Dropdown>
