## 3. **Diff Fetching Data Flow**

**API Layer:** `/Users/stephanostsoucas/gossamer/app/src/renderer/src/api.ts` (lines 134-144)

```typescript
export async function fetchCheckpointDiff(checkpointId: string): Promise<string | null> {
  const res = await fetch(`${API_BASE}/v2/checkpoints/${encodeURIComponent(checkpointId)}/diff`);
  if (!res.ok) return null;
  return res.text();
}

export async function fetchCheckpointDiffStats(checkpointId: string): Promise<FileDiffStat[]> {
  const res = await fetch(`${API_BASE}/v2/checkpoints/${encodeURIComponent(checkpointId)}/diff-stats`);
  if (!res.ok) return [];
  return res.json() as Promise<FileDiffStat[]>;
}
```

**Backend Implementation:** `/Users/stephanostsoucas/gossamer/src/server.ts` (lines 463-480)

```typescript
app.get("/api/v2/checkpoints/:id/diff", async (req, res) => {
  try {
    if (!repoDir) { res.status(404).end(); return; }
    const join = await db.checkpointIdGitOidJoin.findFirst({
      where: { checkpointId: req.params.id },
      select: { gitOid: true },
    });
    if (!join) { res.status(404).end(); return; }
    const { stdout } = await exec(
      `git -C ${JSON.stringify(repoDir)} diff-tree -p --no-commit-id -r ${join.gitOid}`,
    );
    res.set("Content-Type", "text/plain; charset=utf-8");
    res.send(stdout);
  } catch {
    res.status(500).end();
  }
});
```

**Key Steps:**
1. Look up the git OID from `CheckpointIdGitOidJoin` using the checkpoint ID
2. If found, execute `git diff-tree -p` command with that OID
3. Return the unified diff output as plain text
4. If not found or error occurs, return 404/500

