  db: PrismaClient,
  checkpointDir: string,
  checkpointId: string,
  repoPath?: string,
  mappedCheckpointIds?: Set<string>,
): Promise<void> {
  const metaPath = join(checkpointDir, "metadata.json");
  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);

