import { execSync } from "child_process";

export function getCheckpointIdFromCommitMessage(message: string): string | null {
  const match = message.match(/^Entire-Checkpoint:\s*(\S+)$/m);
  return match ? match[1] : null;
}

export async function findCommitForCheckpoint(
  repoPath: string,
  _branch: string,
  checkpointId: string,
): Promise<{ hash: string; subject: string; branch: string; authorName: string; authorEmail: string } | null> {
  // Use `git log --all --grep` to find the commit across every ref in a single query.
  // This is O(1) queries regardless of history depth and covers deleted/renamed branches.
  try {
    const raw = execSync(
      `git -C ${JSON.stringify(repoPath)} log --all --grep=${JSON.stringify("Entire-Checkpoint: " + checkpointId)} -1 --format=%H%x00%s%x00%an%x00%ae`,
      { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] },
    ).trim();
    if (!raw) return null;
    const [hash, subject, authorName, authorEmail] = raw.split("\x00");
    if (!hash) return null;
    // Determine which branch this commit is on (first match wins).
    let branch = _branch;
    try {
      const refs = execSync(
        `git -C ${JSON.stringify(repoPath)} branch --all --contains ${hash} --format=%(refname:short)`,
        { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] },
      ).trim();
      const first = refs.split("\n").find(Boolean);
      if (first) branch = first.replace(/^origin\//, "");
    } catch { /* branch name is best-effort */ }
    return { hash, subject, branch, authorName, authorEmail };
  } catch {
    return null;
  }
}
